class Solution:
    def numberOfPoints(self, nums):
        intervals = sorted(nums)
        total = 0
        cur_s = None
        cur_e = None
        for s, e in intervals:
            if cur_s is None:
                cur_s, cur_e = s, e
            elif s <= cur_e + 1:
                cur_e = max(cur_e, e)
            else:
                total += cur_e - cur_s + 1
                cur_s, cur_e = s, e
        if cur_s is not None:
            total += cur_e - cur_s + 1
        return total

